/**
 * generate-depcruiser.js
 * =======================
 * Generates .dependency-cruiser.cjs from the Architecture Matrix.
 *
 * Usage:
 *   node scripts/architecture/generate-depcruiser.js
 *
 * DO NOT edit .dependency-cruiser.cjs directly.
 */

'use strict';

const fs = require('fs');
const path = require('path');
const { CORE_NAMESPACES, PACKAGE_BOUNDARY_RULES, EXCEPTIONS } = require('./matrix.js');

// ─── Build forbidden rules from core namespace matrix ─────────────────────────

function buildCoreNamespaceRules() {
  const rules = [];

  for (const ns of CORE_NAMESPACES) {
    if (!ns.forbiddenDeps || ns.forbiddenDeps.length === 0) continue;

    for (const forbidden of ns.forbiddenDeps) {
      const forbiddenPattern = forbidden.replace('core/src/', 'src/').replace(/\//g, '\\/');
      const fromPattern = ns.pathPattern.replace(/\^/, '').replace(/\//g, '\\/').replace(/\/$/, '');

      // Check if there's an exception for this pair
      const hasException = EXCEPTIONS.some(
        e => e.ruleId && e.ruleId.includes(ns.id.replace('core-', ''))
      );

      const ruleId = `${ns.id}-no-${forbidden.split('/').pop()}`;

      rules.push({
        name: ruleId,
        comment: `[Matrix] ${ns.label} must not import from ${forbidden}`,
        severity: 'error',
        from: { path: ns.pathPattern },
        to: {
          path: `^${forbidden.replace(/\//g, '\\/')}/`,
          pathNot: hasException ? EXCEPTIONS
            .filter(e => e.ruleId === ruleId)
            .map(e => e.to)
            .join('|') : undefined,
        },
      });
    }
  }

  return rules;
}

// ─── Build package boundary rules ─────────────────────────────────────────────

function buildPackageBoundaryRules() {
  return PACKAGE_BOUNDARY_RULES.map(rule => ({
    name: rule.id,
    comment: `[Matrix] ${rule.message}`,
    severity: rule.severity,
    from: { path: rule.from.pathPattern },
    to: { path: rule.forbidden.pathPattern },
  }));
}

// ─── Build the full config ─────────────────────────────────────────────────────

function buildConfig() {
  const coreRules = buildCoreNamespaceRules();
  const packageRules = buildPackageBoundaryRules();

  // Standard built-in rules
  const standardRules = [
    {
      name: 'no-circular',
      comment: '[Governance] No circular dependencies allowed anywhere in core',
      severity: 'error',
      from: { path: '^core/src/' },
      to: {
        circular: true,
      },
    },
    {
      name: 'no-orphans',
      comment: '[Governance] Warn on orphaned modules',
      severity: 'warn',
      from: {
        orphan: true,
        pathNot: [
          '\\.d\\.ts$',
          '(^|/)\\.[^/]+\\.(js|cjs|mjs|ts|json)$',
          '\\.spec\\.ts$',
          '\\.test\\.ts$',
          '__tests__',
          '__mocks__',
        ],
      },
      to: {},
    },
    {
      name: 'no-non-package-json-deps',
      comment: '[Governance] Only import declared dependencies',
      severity: 'warn',
      from: {},
      to: {
        dependencyTypes: ['npm-no-pkg', 'npm-unknown'],
      },
    },
  ];

  return {
    forbidden: [...packageRules, ...coreRules, ...standardRules],
    options: {
      doNotFollow: {
        path: 'node_modules',
        dependencyTypes: [
          'npm',
          'npm-dev',
          'npm-optional',
          'npm-peer',
          'npm-bundled',
          'npm-no-pkg',
        ],
      },
      exclude: {
        path: [
          '(^|/)node_modules/',
          '\\.spec\\.ts$',
          '\\.test\\.ts$',
          '(^|/)__tests__/',
          '(^|/)__mocks__/',
          '(^|/)dist/',
          '(^|\\.next)',
        ],
      },
      tsConfig: {
        fileName: 'tsconfig.json',
      },
      enhancedResolveOptions: {
        exportsFields: ['exports'],
        conditionNames: ['import', 'require', 'node', 'default'],
        mainFields: ['module', 'main', 'types', 'typings'],
      },
      reporterOptions: {
        dot: {
          collapsePattern: '^node_modules/(?:@[^/]+/[^/]+|[^/]+)',
        },
      },
    },
  };
}

// ─── Write the file ───────────────────────────────────────────────────────────

const config = buildConfig();
const outputPath = path.resolve(__dirname, '../../.dependency-cruiser.cjs');

const header = `/**
 * .dependency-cruiser.cjs
 * ========================
 * AUTO-GENERATED — DO NOT EDIT MANUALLY
 * 
 * Generated by: scripts/architecture/generate-depcruiser.js
 * Source of truth: scripts/architecture/matrix.js
 * Architecture Version: ${require('./matrix.js').ARCHITECTURE_VERSION}
 * Generated: ${new Date().toISOString()}
 *
 * To regenerate:
 *   node scripts/architecture/generate-depcruiser.js
 */

/** @type {import('dependency-cruiser').IConfiguration} */
module.exports = `;

const output = header + JSON.stringify(config, null, 2) + ';\n';

fs.writeFileSync(outputPath, output, 'utf8');
console.log(`✅ Generated .dependency-cruiser.cjs from matrix.js (${config.forbidden.length} rules)`);
console.log(`   Output: ${outputPath}`);
